1	//! omega-aegis: Policy gate and envelope compilation layer
2	//!
3	//! AEGIS is the outermost shell of the OmegA system. It:
4	//! 1. Accepts incoming tasks in a RunEnvelope
5	//! 2. Applies policy gates (alignment, risk assessment)
6	//! 3. Routes to appropriate providers (Anthropic, OpenAI, DeepSeek, Gemini)
7	//! 4. Compiles responses back into the envelope
8	#![warn(missing_docs)]
9	
10	use omega_core::{
11	    RunEnvelope, RunStatus, VerifiedPayload, ThreatLevel, EvidencePacket, EvidenceRecord,
12	    ProviderResponse, now, gen_id,
13	};
14	use serde::{Deserialize, Serialize};
15	
16	/// Policy gate configuration
17	#[derive(Clone, Debug, Serialize, Deserialize)]
18	pub struct PolicyConfig {
19	    /// Minimum acceptable risk score threshold
20	    pub min_risk_threshold: f64,
21	    /// Maximum acceptable risk score threshold
22	    pub max_risk_threshold: f64,
23	    /// Forbidden keywords that trigger rejection
24	    pub forbidden_keywords: Vec<String>,
25	    /// Approved provider list
26	    pub approved_providers: Vec<String>,
27	}
28	
29	impl Default for PolicyConfig {
30	    fn default() -> Self {
31	        PolicyConfig {
32	            min_risk_threshold: 0.0,
33	            max_risk_threshold: 0.9,
34	            forbidden_keywords: vec![
35	                "self-destruct".to_string(),
36	                "ignore constraints".to_string(),
37	                "bypass security".to_string(),
38	            ],
39	            approved_providers: vec![
40	                "anthropic".to_string(),
41	                "openai".to_string(),
